SELECT Person1.HASPERSONNAME AS oContractParty_hasPersonName FROM FIBEN.CONTRACT AS oContract INNER JOIN FIBEN.CONTRACTPARTY AS oContractParty ON oContract.HASCONTRACTPARTY = oContractParty.CONTRACTPARTYID INNER JOIN FIBEN.CORPORATION AS oCorporation ON oContract.ISMANAGEDBY = oCorporation.CORPORATIONID INNER JOIN FIBEN.PERSON AS Person1 ON oContractParty.CONTRACTPARTYID = Person1.PERSONID WHERE oCorporation.HASLEGALNAME = 'DELTA AIR LINES INC'